local function X(X,f,A,K,k,c,r,B)X:AddSeperator({Title="Discord Webhook"})X:AddToggle({Title="Enable Discord Webhook";Description="Send fish caught to Discord";Default=_G.Config.DiscordWebhookEnabled;Callback=function(X)_G.Config.DiscordWebhookEnabled=X if X then print("Discord Webhook: ENABLED")else print("Discord Webhook: DISABLED")end end})X:AddInput({Title="Discord Webhook URL";Default=_G.Config.DiscordWebhookURL or"";Placeholder="https://discord.com/api/webhooks/...";Callback=function(X)_G.Config.DiscordWebhookURL=X print("Discord Webhook URL updated")end})A:AddToggle({Title="Auto Teleport on Load",Description="Teleport when loading";Default=true;Callback=function(X)_G.Config.AutoTeleportOnLoad=X print("[Config] Auto TP: "..(X and"ON"or"OFF"))updateStatusDisplay()end})A:AddDropdown({Title="Load Config",Description="Select to load";Options=savedConfigsList,Default=savedConfigsList[1];Callback=function(X)if X~="No Configs"then loadConfig(X,_G.Config.AutoTeleportOnLoad)currentConfigFile=X task.wait(.2)updateStatusDisplay()end end})customConfigName=""A:AddInput({Title="Config Name",Description="Enter new name",Default="";Placeholder="MyConfig";Callback=function(X)customConfigName=X end})A:AddButton({Title="Save New Config",Description="Create with name above",ClipsDescendants=true,Callback=function()if customConfigName~=""then local X=customConfigName:gsub("[^%w%s-_]","")saveConfig(X)customConfigName=""end end})A:AddButton({Title="Save Current";Description="Update current file",ClipsDescendants=true;Callback=function()saveConfig(currentConfigFile)end})A:AddButton({Title="Load + Teleport";Description="Load and TP";ClipsDescendants=true,Callback=function()loadConfig(currentConfigFile,true)end})A:AddButton({Title="Load Only";Description="No teleport";ClipsDescendants=true,Callback=function()loadConfig(currentConfigFile,false)end})A:AddButton({Title="Teleport Now";Description="Go to saved position";ClipsDescendants=true,Callback=function()if _G.Config.SavedPosition the