"HumanoidRootPart")or f:FindFirstChild("Head")or f.PrimaryPart if root then cachedNpcLocations[f.Name]=root.CFrame end end end end end if workspace:FindFirstChild("world")and workspace.world:FindFirstChild("npcs")then workspace.world.npcs.ChildAdded:Connect(function(X)task.wait(1)if X:IsA("Model")then root=X:FindFirstChild("HumanoidRootPart")or X:FindFirstChild("Head")or X.PrimaryPart if root then cachedNpcLocations[X.Name]=root.CFrame if updateNpcList and NpcDropdown then updateNpcList()if NpcDropdown.SetValues then NpcDropdown:SetValues(npcNames)elseif NpcDropdown.SetOptions then NpcDropdown:SetOptions(npcNames)end end end end end)end npcNames={}function updateNpcList()cacheCurrentNpcs()npcNames={}for X,f in pairs(cachedNpcLocations)do table.insert(npcNames,X)end table.sort(npcNames)end updateNpcList()end return X